def _unfilter(scanline: bytes, filter_type: int, previous: bytes | None, bpp: int) -> bytes:
    if filter_type == 0:
        return scanline
    if previous is None:
        previous = bytes(len(scanline))

    output = bytearray(len(scanline))
    for index in range(len(scanline)):
        left = output[index - bpp] if index >= bpp else 0
        up = previous[index]
        upper_left = previous[index - bpp] if index >= bpp else 0
        value = scanline[index]
        if filter_type == 1:
            reconstructed = (value + left) & 0xFF
        elif filter_type == 2:
            reconstructed = (value + up) & 0xFF
        elif filter_type == 3:
            reconstructed = (value + ((left + up) // 2)) & 0xFF
        elif filter_type == 4:
            reconstructed = (value + _paeth(left, up, upper_left)) & 0xFF
        else:
            raise ValueError(f"Unsupported PNG filter type: {filter_type}")
        output[index] = reconstructed
    return bytes(output)

